from django.contrib.auth import get_user_model from django.db.models.signals import post_save from django.dispatch import receiver from django.contrib.auth.models import Group, Permission from django.contrib.contenttypes.models import ContentType
from desserts.models import Dessert, Category, Ingredient from orders.models import Order, OrderItem from .models import Profile
User = get_user_model()
@receiver(post_save, sender=User) def create_profile_for_new_user(sender, instance, created, **kwargs): if created: Profile.objects.create(user=instance)
@receiver(post_save, sender=User) def add_user_to_customers_group(sender, instance, created, **kwargs): if created: customers_group, _ = Group.objects.get_or_create(name="Customers") instance.groups.add(customers_group)
def create_default_groups(): customers_group, _ = Group.objects.get_or_create(name="Customers") staff_group, _ = Group.objects.get_or_create(name="Staff")
# Staff permissions: пълен контрол върху десерти, категории, съставки dessert_ct = ContentType.objects.get_for_model(Dessert) category_ct = ContentType.objects.get_for_model(Category) ingredient_ct = ContentType.objects.get_for_model(Ingredient)
staff_permissions = Permission.objects.filter( content_type__in=[dessert_ct, category_ct, ingredient_ct] ) staff_group.permissions.set(staff_permissions)
# Customers permissions: работа с поръчки order_ct = ContentType.objects.get_for_model(Order) orderitem_ct = ContentType.objects.get_for_model(OrderItem)
customer_permissions = Permission.objects.filter( content_type__in=[order_ct, orderitem_ct] ) customers_group.permissions.set(customer_permissions)

from django.contrib.auth import get_user_model from django.db.models.signals import post_save from django.dispatch import receiver from django.contrib.auth.models import Group, Permission from django.contrib.contenttypes.models import ContentType
from desserts.models import Dessert, Category, Ingredient from orders.models import Order, OrderItem from .models import Profile from core.models import Basket
User = get_user_model()
@receiver(post_save, sender=User) def create_profile_for_new_user(sender, instance, created, **kwargs): if created: Profile.objects.create(user=instance)
@receiver(post_save, sender=User) def add_user_to_customers_group(sender, instance, created, **kwargs): if created: customers_group, _ = Group.objects.get_or_create(name="Customers") instance.groups.add(customers_group)
@receiver(post_save, sender=Profile) def create_basket_for_new_profile(sender, instance, created, **kwargs): if created: Basket.objects.create(user=instance.user)
def create_default_groups(): customers_group, _ = Group.objects.get_or_create(name="Customers") staff_group, _ = Group.objects.get_or_create(name="Staff")
# Staff permissions: пълен контрол върху десерти, категории, съставки dessert_ct = ContentType.objects.get_for_model(Dessert) category_ct = ContentType.objects.get_for_model(Category) ingredient_ct = ContentType.objects.get_for_model(Ingredient)
staff_permissions = Permission.objects.filter( content_type__in=[dessert_ct, category_ct, ingredient_ct] ) staff_group.permissions.set(staff_permissions)
# Customers permissions: работа с поръчки order_ct = ContentType.objects.get_for_model(Order) orderitem_ct = ContentType.objects.get_for_model(OrderItem)
customer_permissions = Permission.objects.filter( content_type__in=[order_ct, orderitem_ct] ) customers_group.permissions.set(customer_permissions)

from django.core.management.base import BaseCommand
from django.contrib.auth import get_user_model
from core.models import Basket

class Command(BaseCommand):
    help = 'Create baskets for users who do not have one.'

    def handle(self, *args, **options):
        User = get_user_model()
        created_count = 0
        for user in User.objects.all():
            if not hasattr(user, 'basket'):
                Basket.objects.create(user=user)
                created_count += 1
        self.stdout.write(self.style.SUCCESS(f'Created {created_count} missing baskets.'))

from django.db import models
from django.conf import settings
from desserts.models import Dessert

# Create your models here.

class Basket(models.Model):
    user = models.OneToOneField(settings.AUTH_USER_MODEL, on_delete=models.CASCADE, related_name="basket")
    created_at = models.DateTimeField(auto_now_add=True)

    def total_price(self):
        return sum(item.line_total() for item in self.items.all())

    def __str__(self):
        return f"Basket for {self.user.username}"

class BasketItem(models.Model):
    basket = models.ForeignKey(Basket, on_delete=models.CASCADE, related_name="items")
    dessert = models.ForeignKey(Dessert, on_delete=models.CASCADE)
    quantity = models.PositiveIntegerField(default=1)

    def line_total(self):
        return self.dessert.price * self.quantity

    def __str__(self):
        return f"{self.quantity}x {self.dessert.name} in basket of {self.basket.user.username}"

