    background-color: #444a45;
    color: #e0cfbe;
    border-radius: 12px;
}

.delete-box p,
.delete-box strong {
    color: #e0cfbe !important;
}


.dessert-detail-wrapper {
    display: flex;
    gap: 2rem;
}


.dessert-detail-left,
.dessert-detail-right {
    flex: 1;
}

.dessert-details-box {
    background-color: #444a45;
    color: #e0cfbe;
    border-radius: 12px;
    padding: 2rem;
    height: 100%;

    flex-direction: column;
    justify-content: space-between;
}

.dessert-detail-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    border-radius: 12px;
}

.dessert-detail-left {
    display: flex;
}

.dessert-detail-img {
    flex: 1;
}

.category-card {
    background-color: #444a45;
    color: #e0cfbe;
    border-radius: 12px;
    transition: transform 0.25s ease, box-shadow 0.25s ease;
}

.category-card:hover {
    transform: translateY(-6px);
    box-shadow: 0 12px 24px rgba(0,0,0,0.18);
}

.category-title {
    font-family: 'Playfair Display', serif;
    font-size: 1.4rem;
    margin: 0;
}

.category-card-link {
    text-decoration: none;
    color: inherit;
}

.category-description-box {
    background-color: #444a45;
    color: #e0cfbe;
    border-radius: 12px;
}

.category-form-box {
    background-color: #444a45;
    color: #e0cfbe;
    border-radius: 12px;
}

.category-form-box label {
    color: #e0cfbe !important;
    font-weight: 500;
}

.category-form-box input,
.category-form-box textarea {
    background-color: #e0cfbe;
    border: none;
    border-radius: 6px;
    padding: 0.6rem;
    width: 100%;
}

.category-form-box input:focus,
.category-form-box textarea:focus {
    outline: 2px solid #d4c2b0;
    background-color: #f3e8dc;
}


.basket-table {
    background-color: transparent !important;
    border-color: #e0cfbe !important;
    color: #e0cfbe !important;
}

.basket-table thead {
    background-color: #333 !important;
    border-bottom: 2px solid #e0cfbe !important;
}

.basket-table thead th {
    color: #e0cfbe !important;
    border-color: #e0cfbe !important;
    border-bottom: 2px solid #e0cfbe !important;
    font-weight: 600;
    text-align: left;
    padding: 1rem 0.75rem !important;
    background-color: #333 !important;
}

.basket-table tbody tr {
    border-bottom: 1px solid #e0cfbe !important;
    background-color: transparent !important;
}

.basket-table tbody tr:hover {
    background-color: rgba(224, 207, 190, 0.1) !important;
}

.basket-table tbody td {
    color: #e0cfbe !important;
    border-color: #e0cfbe !important;
    padding: 1rem 0.75rem !important;
    vertical-align: middle !important;
    background-color: transparent !important;
}

.basket-link {
    color: #e0cfbe !important;
    text-decoration: none !important;
}

/* Basket Quantity Controls */
.btn-outline-success,
.btn-outline-warning {
    color: #e0cfbe !important;
    border-color: #e0cfbe !important;
}

.btn-outline-success:hover {
    background-color: #28a745 !important;
    border-color: #28a745 !important;
    color: white !important;
}

.btn-outline-warning:hover {
    background-color: #ffc107 !important;
    border-color: #ffc107 !important;
    color: #333 !important;
}

{% extends "base.html" %}
{% load static %}
{% load dessert_filters %}

{% block title %}{{ dessert.name }}{% endblock %}

{% block content %}
<div class="container py-5" style="padding-top: 7rem;">

    <div class="dessert-detail-wrapper">

        <div class="dessert-detail-left">
            {% if dessert.image %}
                <img src="{{ dessert.image.url }}" alt="{{ dessert.name }}" class="dessert-detail-img shadow">
            {% else %}
                <img src="{% static 'media/no-image.jpg' %}" class="dessert-detail-img shadow" alt="No image">
            {% endif %}
        </div>

        <div class="dessert-detail-right">
            <div class="dessert-details-box p-4 rounded shadow">

                <h2 class="mb-3">{{ dessert.name }}</h2>

                <p><strong>Description:</strong> {{ dessert.description }}</p>

                <p><strong>Price:</strong> {{ dessert.price|euro }}</p>

                <p><strong>Category:</strong> {{ dessert.category.name }}</p>

                <h4 class="mt-4">Ingredients:</h4>
                <ul>
                    {% for ingredient in dessert.ingredients.all %}
                        <li>{{ ingredient.name }}</li>
                    {% empty %}
                        <li>No ingredients listed.</li>
                    {% endfor %}
                </ul>

                <p class="mt-3"><strong>Available:</strong> {{ dessert.is_available|yesno:"Yes,No" }}</p>

                {% if user.is_staff %}
                    <div class="mt-4 d-flex gap-3">
                        <a href="{% url 'dessert_edit' dessert.pk %}" class="btn btn-green btn-lg">Edit</a>
                        <a href="{% url 'dessert_delete' dessert.pk %}" class="btn btn-green btn-lg">Delete</a>
                    </div>
                {% endif %}
            </div>
        </div>



    </div>
    <h3 class="mt-5">Reviews</h3>

            {% for review in dessert.reviews.all %}
                <div class="border rounded p-3 mb-3">
                    <strong>{{ review.user.username }}</strong> — {{ review.rating }}/5
                    <p>{{ review.comment }}</p>

                    {% if review.user == user %}
                        <a href="{% url 'review_edit' review.pk %}" class="btn btn-sm btn-green">Edit</a>
                        <a href="{% url 'review_delete' review.pk %}" class="btn btn-sm btn-danger">Delete</a>
                    {% endif %}
                </div>
            {% empty %}
                <p>No reviews yet.</p>
            {% endfor %}

        {% if user.is_authenticated %}
            {% if not user_has_reviewed %}
                <a href="{% url 'review_add' dessert.pk %}" class="btn btn-green btn-lg mt-3">
                    Add Review
                </a>
            {% endif %}
        {% else %}
            <p class="mt-3">You must <a href="{% url 'login' %}">log in</a> to leave a review.</p>
        {% endif %}

</div>
{% endblock %}

